package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.apache.commons.csv.CSVFormat;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;

class CSVFormatTest {

    @Test
    void testGetAllowMissingColumnNames_default() {
        CSVFormat format = CSVFormat.DEFAULT;
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNames() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNames_boolean_true() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(true);
        assertTrue(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_withAllowMissingColumnNames_boolean_false() {
        CSVFormat format = CSVFormat.DEFAULT.withAllowMissingColumnNames(false);
        assertFalse(format.getAllowMissingColumnNames());
    }

    @Test
    void testGetAllowMissingColumnNames_EXCEL_constant() throws Exception {
        // Use reflection to access the private field allowMissingColumnNames in CSVFormat.EXCEL
        CSVFormat excelFormat = CSVFormat.EXCEL;
        Field field = CSVFormat.class.getDeclaredField("allowMissingColumnNames");
        field.setAccessible(true);
        boolean value = field.getBoolean(excelFormat);
        assertTrue(value);
    }

}
